/* === utilities.js === */
/* utilities.js — Shared constants and helper functions */

'use strict';

/* Master header injection: standardize header across all pages using Home page header as source of truth
   NOTE: Skip blog pages (blog-1, blog-2, ...) as requested by the user. */
(function(){
  try {
    var p = (location && location.pathname) ? location.pathname : '';
    // If path contains a blog folder like /blog-1/ or /blog-2/, skip injection
    if ((/^\/?blog-\d+/).test(p) || /(^|\/)blog-\d+(\/|$)/.test(p)) return;

    var MASTER_HEADER_HTML = `
<header id="site-header">
  <div class="hdr-inner">
    <div class="hdr-left hdr-brand">
      <a href="/" class="logo-link">
        <div class="logo-icon">
          <img src="/assets/images/Morning-Star-Infra-Projects-Header-Logo.jpeg" alt="Morning Star Infra Projects logo">
        </div>
        <div class="logo-text">
          <span class="logo-main">MORNING STAR</span>
          <span class="logo-sub">INFRA PROJECTS</span>
        </div>
      </a>
    </div>
    <nav class="hdr-nav">
      <a class="nav-link" href="/" data-page="home">Home</a>
      <a class="nav-link" href="/pages/our-story.html" data-page="story">Our Story</a>
      <a class="nav-link" href="/pages/our-team.html" data-page="team">Our Team</a>
      <div class="nav-dropdown">
        <span class="nav-link nav-drop-trigger">Divisions ▾</span>
        <div class="nav-drop-menu">
          <a class="drop-link" href="/pages/home-construction.html">Home Construction</a>
          <a class="drop-link" href="/pages/commercial-and-industrial.html">Commercial &amp; Industrial</a>
          <a class="drop-link" href="/pages/interior-fitouts.html">Interior Fitouts</a>
          <a class="drop-link" href="/pages/structural-repair.html">Structural Repair</a>
        </div>
      </div>
      <a class="nav-link" href="/pages/certifications.html" data-page="certifications">Certifications</a>
      <a class="nav-link" href="/pages/blog.html" data-page="blog">Blog</a>
      <a class="nav-cta" href="#quote" onclick="openModal();return false;">Get Quote</a>
    </nav>
    <button id="hamburger" class="hamburger">
      <span></span>
      <span></span>
      <span></span>
    </button>
  </div>
  <div id="mobile-menu" class="mobile-menu">
    <a class="mob-link" href="/" data-page="home">Home</a>
    <a class="mob-link" href="/pages/our-story.html" data-page="story">Our Story</a>
    <a class="mob-link" href="/pages/our-team.html" data-page="team">Our Team</a>
    <div class="mob-divider" style="padding:8px 16px 4px;color:var(--text);font-weight:700">Divisions</div>
    <a class="mob-link" href="/pages/home-construction.html">Home Construction</a>
    <a class="mob-link" href="/pages/commercial-and-industrial.html">Commercial &amp; Industrial</a>
    <a class="mob-link" href="/pages/interior-fitouts.html">Interior Fitouts</a>
    <a class="mob-link" href="/pages/structural-repair.html">Structural Repair</a>
    <a class="mob-link" href="/pages/certifications.html" data-page="certifications">Certifications</a>
    <a class="mob-link" href="/pages/blog.html" data-page="blog">Blog</a>
    <a class="mob-cta" href="#quote" onclick="openModal();return false;">Get Quote</a>
  </div>
</header>`;

    var existing = document.getElementById('site-header');
    if (existing) {
      // Replace outerHTML to ensure full structure is identical
      existing.outerHTML = MASTER_HEADER_HTML;
    } else {
      // If no header present, insert at top of body
      document.body.insertAdjacentHTML('afterbegin', MASTER_HEADER_HTML);
    }

    // Header height updater (previously inline on Home page)
    function updateHeaderHeight(){
      var header = document.getElementById('site-header');
      if(!header) return;
      var h = Math.ceil(header.getBoundingClientRect().height);
      document.documentElement.style.setProperty('--hdr-h', h + 'px');
    }
    window.addEventListener('load', updateHeaderHeight);
    window.addEventListener('resize', updateHeaderHeight);
    var hdr = document.getElementById('site-header');
    if(hdr && window.MutationObserver){
      var obs = new MutationObserver(function(){ updateHeaderHeight(); });
      obs.observe(hdr, { childList: true, subtree: true, attributes: true });
    }
  } catch (e) { console.error(e); }
})();

const REDUCE_MOTION = window.matchMedia && window.matchMedia('(prefers-reduced-motion: reduce)').matches;

const RESIZE_HANDLERS = new Set();
let _resizeRaf = null;
function runResizeHandlers() {
  if (_resizeRaf) return;
  _resizeRaf = requestAnimationFrame(() => {
    RESIZE_HANDLERS.forEach(fn => { try { fn(); } catch(e) {} });
    _resizeRaf = null;
  });
}
window.addEventListener('resize', runResizeHandlers, { passive: true });

function validatePhone(p) { return /^[6-9]\d{9}$/.test(p.replace(/[\s\-]/g,'')); }
function validateEmail(e) { return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(e); }

function ensureMeta(sel, attrName, attrVal) {
  let m = document.querySelector(sel);
  if (!m) { m = document.createElement('meta'); if (attrName) m.setAttribute(attrName, attrVal); document.head.appendChild(m); }
  return m;
}


/* === mpa-nav.js === */
/* mpa-nav.js — Navigation for standalone MPA pages
   Morning Star Infra Projects
   Handles: hamburger, header scroll shadow, active nav link, DOM cache for sliders */

// ── Hamburger ────────────────────────────────────────────────────────────────
(function() {
  var hamburger = document.getElementById('hamburger');
  var mobileMenu = document.getElementById('mobile-menu');
  if (!hamburger || !mobileMenu) return;
  hamburger.addEventListener('click', function() {
    var open = mobileMenu.classList.toggle('open');
    hamburger.setAttribute('aria-expanded', open);
    document.body.style.overflow = open ? 'hidden' : '';
  });
  mobileMenu.querySelectorAll('.mob-link, .mob-cta').forEach(function(el) {
    el.addEventListener('click', function() {
      mobileMenu.classList.remove('open');
      hamburger.setAttribute('aria-expanded', 'false');
      document.body.style.overflow = '';
    });
  });
})();

// ── Header scroll shadow ─────────────────────────────────────────────────────
(function() {
  var hdr = document.getElementById('site-header');
  if (!hdr) return;
  window.addEventListener('scroll', function() {
    hdr.classList.toggle('scrolled', window.scrollY > 20);
  }, { passive: true });
})();

// ── Active nav link (enhanced) ───────────────────────────────────────────────
(function() {
  var rawPath = window.location.pathname || '/';
  // Normalize path: remove trailing slash (unless root) and remove /index.html
  function normalizePath(p){
    try { p = decodeURIComponent(p); } catch(e){}
    p = p.replace(/\/index\.html$/i,'');
    // remove trailing .html for robust matching between friendly slugs and file paths
    p = p.replace(/\.html$/i, '');
    if (p.length > 1) p = p.replace(/\/$/,'');
    return p || '/';
  }
  var path = normalizePath(rawPath);

  // Alias map for friendly slugs -> canonical page paths
  var ALIAS_MAP = {
    '/residential': '/pages/home-construction',
    '/industrial':  '/pages/commercial-and-industrial',
    '/interiors':   '/pages/interior-fitouts',
    '/structural':  '/pages/structural-repair'
  };

  function resolveAlias(p){
    if(!p) return p;
    return ALIAS_MAP[p] || p;
  }

  function clearAllActive(){
    document.querySelectorAll('.nav-link.active, .drop-link.active, .mob-link.active, .nav-drop-trigger.active').forEach(function(el){
      el.classList.remove('active');
      el.removeAttribute('aria-current');
    });
  }

  function setActiveEls(els){
    if (!els || els.length === 0) return;
    clearAllActive();
    els.forEach(function(el){ el.classList.add('active'); el.setAttribute('aria-current','page'); });
  }

  // Normalize href to comparable path
  function hrefPath(href){
    if (!href) return '';
    // allow anchor or javascript void
    if (/^#|^javascript:/i.test(href)) return '';
    // create anchor to parse
    var a = document.createElement('a'); a.href = href;
    return normalizePath(a.pathname || a.getAttribute('href'));
  }

  // Collect nav items
  var navItems = Array.from(document.querySelectorAll('.nav-link, .drop-link, .mob-link'));

  // 1) Exact href path match or prefix match (child pages)
  for (var i=0;i<navItems.length;i++){
    var el = navItems[i];
    var hp = hrefPath(el.getAttribute('href'));
    if (!hp) continue;
    var hpResolved = resolveAlias(hp);
    var pathResolved = resolveAlias(path);
    if (hp === path || hpResolved === path || path === hp + '' || path.indexOf(hp + '/') === 0 || path.indexOf(hpResolved + '/') === 0 || hpResolved === pathResolved) {
      // mark the canonical desktop/mobile counterparts by data-page when available
      var page = el.getAttribute('data-page');
      if (page) {
        var matches = Array.from(document.querySelectorAll('.nav-link[data-page="' + page + '"], .mob-link[data-page="' + page + '"]'));
        setActiveEls(matches);
      } else {
        // If the matched element is a dropdown child (drop-link), also highlight the
        // dropdown trigger and mobile equivalents so the parent shows active state.
        if (el.classList && el.classList.contains('drop-link')) {
          var triggerEl = document.querySelector('.nav-drop-trigger');
          var mobMatches = Array.from(document.querySelectorAll('.mob-link')).filter(function(m){
            var mh = hrefPath(m.getAttribute('href'));
            return mh && (mh === hp || path.indexOf(mh) === 0);
          });
          var toSet = [el];
          if (triggerEl) toSet.push(triggerEl);
          toSet = toSet.concat(mobMatches);
          setActiveEls(toSet);
        } else {
          setActiveEls([el]);
        }
      }
      return; // highest priority
    }
  }

  // 2) Blog grouping: any /blog-<n>/ or path starting with /blog or /pages/blog.html
  var isBlog = /(^|\/)blog-\d+\//i.test(path + '/') || path.indexOf('/blog') === 0 || path === '/pages/blog' || path === '/pages/blog.html' || path === '/blog';
  if (isBlog) {
    var blogEls = Array.from(document.querySelectorAll('.nav-link[data-page="blog"], .mob-link[data-page="blog"]'));
    if (blogEls.length) { setActiveEls(blogEls); return; }
  }

  // 3) Divisions grouping: check drop links inside .nav-drop-menu
  var dropMenu = document.querySelectorAll('.nav-drop-menu .drop-link');
  for (var j=0;j<dropMenu.length;j++){
    var d = dropMenu[j];
    var dh = hrefPath(d.getAttribute('href'));
    if (!dh) continue;
    var dhResolved = resolveAlias(dh);
    if (dh === path || dhResolved === path || path.indexOf(dh + '/') === 0 || path.indexOf(dhResolved + '/') === 0 || path.indexOf(dh) >= 0) {
      // mark dropdown trigger and mobile links matching divisions
      var trigger = document.querySelector('.nav-drop-trigger');
      var mobMatches = Array.from(document.querySelectorAll('.mob-link')).filter(function(m){
        var mh = hrefPath(m.getAttribute('href'));
        var mhResolved = resolveAlias(mh);
        return mh && (mh === dh || mhResolved === dh || path.indexOf(mh) === 0 || path.indexOf(mhResolved) === 0 || (mh.indexOf('residential')>=0 && path.indexOf('residential')>=0));
      });
      var toSet = [];
      if (trigger) toSet.push(trigger);
      toSet = toSet.concat(mobMatches);
      if (toSet.length) { setActiveEls(toSet); return; }
    }
  }

  // 4) About pages
  if (/our-story|story|our-team|team/i.test(path)){
    if (path.indexOf('story')>=0) { setActiveEls(Array.from(document.querySelectorAll('.nav-link[data-page="story"], .mob-link[data-page="story"]'))); return; }
    if (path.indexOf('team')>=0) { setActiveEls(Array.from(document.querySelectorAll('.nav-link[data-page="team"], .mob-link[data-page="team"]'))); return; }
  }

  // 5) Projects / Careers / Contact heuristics
  if (/projects|project-/i.test(path)) { setActiveEls(Array.from(document.querySelectorAll('.nav-link[data-page="projects"], .mob-link[data-page="projects"]'))); return; }
  if (/careers|career/i.test(path)) { setActiveEls(Array.from(document.querySelectorAll('.nav-link[data-page="careers"], .mob-link[data-page="careers"]'))); return; }
  if (/contact/i.test(path)) { setActiveEls(Array.from(document.querySelectorAll('.nav-link[data-page="contact"], .mob-link[data-page="contact"]'))); return; }

  // 6) Fallback: mark Home for root
  if (path === '/' || path === '' ) { setActiveEls(Array.from(document.querySelectorAll('.nav-link[data-page="home"], .mob-link[data-page="home"]'))); }

})();

