/* === forms.js === */
/* forms.js — Modal, Quote Form, FAQ & Accordion Logic */

function openModal() {
  if (D.quoteModal) { D.quoteModal.classList.add('open'); document.body.style.overflow = 'hidden'; }
}
function closeModal() {
  if (D.quoteModal) { D.quoteModal.classList.remove('open'); document.body.style.overflow = ''; }
}

if (D.modalClose) D.modalClose.addEventListener('click', closeModal);
if (D.quoteModal) D.quoteModal.addEventListener('click', function(e){ if (e.target === this) closeModal(); });
document.addEventListener('keydown', e => { if (e.key === 'Escape') closeModal(); });

if (D.quoteForm) D.quoteForm.addEventListener('submit', function(e) {
  e.preventDefault();
  const name    = (D.qfName    && D.qfName.value.trim())    || '';
  const phone   = (D.qfPhone   && D.qfPhone.value.trim())   || '';
  const email   = (D.qfEmail   && D.qfEmail.value.trim())   || '';
  const service = (D.qfService && D.qfService.value)        || '';
  if (!name || name.length < 3)        { alert('Please enter a valid name (min. 3 characters).'); return; }
  if (!validatePhone(phone))           { alert('Please enter a valid 10-digit phone number.'); return; }
  if (email && !validateEmail(email))  { alert('Please enter a valid email address.'); return; }
  if (!service)                        { alert('Please select a service.'); return; }
  const msg = encodeURIComponent(`Hello Morning Star Infra Projects!\n\nName: ${name}\nPhone: ${phone}\nEmail: ${email}\nService: ${service}\nMessage: ${D.qfMsg ? D.qfMsg.value : ''}`);
  window.open(`https://wa.me/918098889984?text=${msg}`, '_blank');
  this.reset();
  closeModal();
});

function toggleFaq(el) {
  const item = el.parentElement;
  const isOpen = item.classList.contains('open');
  (D.faqItems || []).forEach(i => i.classList.remove('open'));
  if (!isOpen) item.classList.add('open');
}

document.addEventListener('DOMContentLoaded', function() {
  document.querySelectorAll('.content.open').forEach(c => c.classList.remove('open'));
  document.querySelectorAll('.accordion-btn span').forEach(s => { s.textContent = '+'; });

  document.querySelectorAll('.accordion').forEach(function(accordion) {
    accordion.addEventListener('click', function(e) {
      const btn = e.target.closest('.accordion-btn');
      if (!btn || !accordion.contains(btn)) return;
      const content = btn.nextElementSibling;
      const icon = btn.querySelector('span');
      if (content.classList.contains('open')) {
        content.classList.remove('open');
        if (icon) icon.textContent = '+';
        return;
      }
      accordion.querySelectorAll('.content.open').forEach(item => item.classList.remove('open'));
      accordion.querySelectorAll('.accordion-btn span').forEach(i => { i.textContent = '+'; });
      content.classList.add('open');
      if (icon) icon.textContent = '-';
      try { content.scrollIntoView({ behavior: 'smooth', block: 'nearest' }); } catch(e) {}
    }, false);
  });

  document.querySelectorAll('.package-card .content li').forEach(function(li) {
    if (li.querySelector('strong')) return;
    const textNode = Array.from(li.childNodes).find(n => n.nodeType === Node.TEXT_NODE && n.textContent.indexOf(':') !== -1);
    if (!textNode) return;
    const text = textNode.textContent;
    const idx = text.indexOf(':');
    if (idx === -1) return;
    const before = text.slice(0, idx).trim();
    const after  = text.slice(idx + 1).trimStart();
    const strong = document.createElement('strong');
    strong.textContent = before + ':';
    const afterNode = document.createTextNode(' ' + after);
    li.replaceChild(afterNode, textNode);
    li.insertBefore(strong, afterNode);
  });
});

window.openModal  = openModal;
window.closeModal = closeModal;
window.toggleFaq  = toggleFaq;


/* === sliders.js === */
/* sliders.js — Drag, Division Carousel, Pricing Carousel, Interior Carousel */

let GLOBAL_DRAG = null;

function globalDragMove(e) {
  if (!GLOBAL_DRAG) return;
  if (GLOBAL_DRAG.rafId) return;
  GLOBAL_DRAG.rafId = requestAnimationFrame(() => {
    const clientX = e.clientX || (e.touches && e.touches[0] && e.touches[0].clientX) || 0;
    const x = clientX - GLOBAL_DRAG.rectLeft;
    const walk = (x - GLOBAL_DRAG.startX) * 1.2;
    if (Math.abs(walk) > 4) GLOBAL_DRAG.hasDragged = true;
    GLOBAL_DRAG.container.scrollLeft = GLOBAL_DRAG.startScrollLeft - walk;
    GLOBAL_DRAG.rafId = null;
  });
}

function globalDragEnd() {
  if (!GLOBAL_DRAG) return;
  const c = GLOBAL_DRAG.container;
  c.classList.remove('is-dragging');
  if (GLOBAL_DRAG.hasDragged) {
    const handler = function(ev) { ev.stopImmediatePropagation(); ev.preventDefault(); c.removeEventListener('click', handler, true); };
    c.addEventListener('click', handler, true);
  }
  if (GLOBAL_DRAG.rafId) cancelAnimationFrame(GLOBAL_DRAG.rafId);
  GLOBAL_DRAG = null;
}

if (!window._globalDragManagerInstalled) {
  window.addEventListener('pointermove', globalDragMove, { passive: true });
  window.addEventListener('pointerup',   globalDragEnd,  { passive: true });
  window.addEventListener('pointercancel', globalDragEnd, { passive: true });
  window._globalDragManagerInstalled = true;
}

function setupDrag(container) {
  if (!container) return { destroy: () => {} };

  // ── Touch: let browser scroll natively (touch-action:pan-x) ─────────────
  // Just track whether container scrolled so we can block post-swipe clicks
  let touchStartScrollLeft = 0;
  let touchDidScroll = false;

  const onTouchStart = (e) => {
    touchStartScrollLeft = container.scrollLeft;
    touchDidScroll = false;
  };

  const onTouchScroll = () => {
    if (Math.abs(container.scrollLeft - touchStartScrollLeft) > 4) {
      touchDidScroll = true;
    }
  };

  const onTouchEnd = () => {
    if (touchDidScroll) {
      // Block the click that fires right after a swipe
      const handler = function(ev) {
        ev.stopImmediatePropagation();
        ev.preventDefault();
        container.removeEventListener('click', handler, true);
      };
      container.addEventListener('click', handler, true);
    }
    touchDidScroll = false;
  };

  container.addEventListener('touchstart', onTouchStart, { passive: true });
  container.addEventListener('scroll',     onTouchScroll, { passive: true });
  container.addEventListener('touchend',   onTouchEnd,    { passive: true });
  container.addEventListener('touchcancel',onTouchEnd,    { passive: true });

  // ── Mouse: JS-controlled drag scroll ─────────────────────────────────────
  const onPointerDown = (e) => {
    if (e.pointerType === 'touch') return; // handled above
    const rect = container.getBoundingClientRect();
    GLOBAL_DRAG = { container, rectLeft: rect.left, startX: e.clientX - rect.left, startScrollLeft: container.scrollLeft, hasDragged: false, rafId: null };
    container.classList.add('is-dragging');
    container.setPointerCapture(e.pointerId);
  };
  container.addEventListener('pointerdown', onPointerDown, { passive: true });

  return {
    destroy() {
      container.removeEventListener('touchstart',  onTouchStart);
      container.removeEventListener('scroll',      onTouchScroll);
      container.removeEventListener('touchend',    onTouchEnd);
      container.removeEventListener('touchcancel', onTouchEnd);
      container.removeEventListener('pointerdown', onPointerDown);
    }
  };
}

// ── Division Slider ──────────────────────────────────────────────────────────
(function initDivisionSlider() {
  const track = D.divisionTrack;
  const progressTrack = D.divisionProgressTrack;
  const progressFill  = D.divisionFill;
  if (!track || !progressTrack || !progressFill) return;

  const updateFill = () => requestAnimationFrame(() => {
    const maxScroll = track.scrollWidth - track.clientWidth;
    progressFill.style.width = (maxScroll <= 0) ? '0%' : ((track.scrollLeft / maxScroll) * 100).toFixed(1) + '%';
  });

  progressTrack.addEventListener('click', (e) => {
    const rect = progressTrack.getBoundingClientRect();
    const ratio = Math.max(0, Math.min(1, (e.clientX - rect.left) / rect.width));
    const maxScroll = track.scrollWidth - track.clientWidth;
    if (maxScroll <= 0) return;
    track.scrollTo({ left: ratio * maxScroll, behavior: REDUCE_MOTION ? 'auto' : 'smooth' });
    updateFill();
  }, { passive: true });

  let _divisionStep = 300;
  const computeDivisionStep = () => { const card = track.querySelector('.div-tab'); _divisionStep = card ? (card.offsetWidth + 18) : 300; };
  computeDivisionStep();
  RESIZE_HANDLERS.add(computeDivisionStep);
  RESIZE_HANDLERS.add(updateFill);

  const scrollByCard = (dir) => { track.scrollBy({ left: dir * _divisionStep, behavior: REDUCE_MOTION ? 'auto' : 'smooth' }); };

  track.querySelectorAll('.div-tab').forEach(tab => {
    tab.addEventListener('keydown', (e) => {
      if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); tab.click(); }
      else if (e.key === 'ArrowLeft')  { e.preventDefault(); scrollByCard(-1); }
      else if (e.key === 'ArrowRight') { e.preventDefault(); scrollByCard(1); }
    });
    tab.addEventListener('focus', () => {
      tab.scrollIntoView({ inline: 'center', block: 'nearest', behavior: REDUCE_MOTION ? 'auto' : 'smooth' });
      updateFill();
      if (D.divisionsAnnounce) D.divisionsAnnounce.textContent = `${tab.querySelector('.div-tab-num')?.textContent||''} ${tab.querySelector('.div-tab-title')?.textContent||''} focused.`;
    });
  });

  setupDrag(track);
  track.addEventListener('scroll', updateFill, { passive: true });
  updateFill();
})();

// ── Pricing Carousel ─────────────────────────────────────────────────────────
(function initPricingCarousel() {
  const grid  = D.pricingGrid;
  const fill  = D.pricingFill;
  const track = D.pricingTrack;
  if (!grid || !fill || !track) return;

  const updateFill = () => requestAnimationFrame(() => {
    const maxScroll = grid.scrollWidth - grid.clientWidth;
    fill.style.width = (maxScroll <= 0) ? '0%' : ((grid.scrollLeft / maxScroll) * 100).toFixed(1) + '%';
  });

  let _pricingStep = 300;
  const computePricingStep = () => { const card = grid.querySelector('.price-card'); _pricingStep = card ? (card.offsetWidth + 20) : 300; };
  computePricingStep();
  RESIZE_HANDLERS.add(computePricingStep);
  RESIZE_HANDLERS.add(updateFill);

  const scrollByCard = (dir) => grid.scrollBy({ left: dir * _pricingStep, behavior: REDUCE_MOTION ? 'auto' : 'smooth' });

  track.addEventListener('click', (e) => {
    const rect = track.getBoundingClientRect();
    const maxScroll = grid.scrollWidth - grid.clientWidth;
    grid.scrollTo({ left: ((e.clientX - rect.left) / rect.width) * maxScroll, behavior: REDUCE_MOTION ? 'auto' : 'smooth' });
    updateFill();
  }, { passive: true });

  grid.querySelectorAll('.price-card').forEach(card => {
    card.addEventListener('keydown', (e) => {
      if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); card.querySelector('button')?.click(); }
      else if (e.key === 'ArrowLeft')  { e.preventDefault(); scrollByCard(-1); }
      else if (e.key === 'ArrowRight') { e.preventDefault(); scrollByCard(1); }
    });
    card.addEventListener('focus', () => {
      card.scrollIntoView({ inline: 'center', block: 'nearest', behavior: REDUCE_MOTION ? 'auto' : 'smooth' });
      if (D.pricingAnnounce) D.pricingAnnounce.textContent = `${card.querySelector('.price-name')?.textContent||'Package'} selected.`;
      updateFill();
    });
  });

  setupDrag(grid);
  grid.addEventListener('scroll', updateFill, { passive: true });
  updateFill();
})();

// ── Interior Carousel ────────────────────────────────────────────────────────
(function initInteriorCarousel() {
  const grid  = D.interiorGrid;
  const fill  = D.interiorFill;
  const track = D.interiorTrack;
  if (!grid || !fill || !track) return;

  const updateFill = () => requestAnimationFrame(() => {
    const maxScroll = grid.scrollWidth - grid.clientWidth;
    fill.style.width = (maxScroll <= 0) ? '0%' : ((grid.scrollLeft / maxScroll) * 100).toFixed(1) + '%';
  });

  let _interiorStep = 300;
  const computeInteriorStep = () => { const card = grid.querySelector('.price-card'); _interiorStep = card ? (card.offsetWidth + 20) : 300; };
  computeInteriorStep();
  RESIZE_HANDLERS.add(computeInteriorStep);
  RESIZE_HANDLERS.add(updateFill);

  const scrollByCard = (dir) => grid.scrollBy({ left: dir * _interiorStep, behavior: REDUCE_MOTION ? 'auto' : 'smooth' });

  track.addEventListener('click', (e) => {
    const rect = track.getBoundingClientRect();
    const maxScroll = grid.scrollWidth - grid.clientWidth;
    grid.scrollTo({ left: ((e.clientX - rect.left) / rect.width) * maxScroll, behavior: REDUCE_MOTION ? 'auto' : 'smooth' });
    updateFill();
  }, { passive: true });

  grid.querySelectorAll('.price-card').forEach(card => {
    card.addEventListener('keydown', (e) => {
      if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); card.querySelector('button')?.click(); }
      else if (e.key === 'ArrowLeft')  { e.preventDefault(); scrollByCard(-1); }
      else if (e.key === 'ArrowRight') { e.preventDefault(); scrollByCard(1); }
    });
    card.addEventListener('focus', () => {
      card.scrollIntoView({ inline: 'center', block: 'nearest', behavior: REDUCE_MOTION ? 'auto' : 'smooth' });
      if (D.interiorAnnounce) D.interiorAnnounce.textContent = `${card.querySelector('.price-name')?.textContent||'Package'} selected.`;
      updateFill();
    });
  });

  setupDrag(grid);
  grid.addEventListener('scroll', updateFill, { passive: true });
  updateFill();
})();


/* === main.js === */
/* main.js — Lucide icons loader & Service Worker */

// Lucide icons: try immediately, fallback to window.load
(function() {
  function initLucide() {
    if (window.lucide && typeof window.lucide.createIcons === 'function') {
      try { window.lucide.createIcons(); } catch(e) {}
    }
  }
  // Try after DOM is ready (Lucide may already be loaded)
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', initLucide);
  } else {
    initLucide();
  }
  // Guaranteed fallback: window load fires after ALL resources including deferred scripts
  window.addEventListener('load', initLucide, { once: true });
  // Also listen on the script element itself
  var s = document.querySelector('script[src*="unpkg.com/lucide"]');
  if (s) s.addEventListener('load', initLucide);
})();

// Service Worker Registration
if ('serviceWorker' in navigator) {
  window.addEventListener('load', () => {
    navigator.serviceWorker.register('./assets/js/service-worker.js').catch(() => {});
  });
}